mapper.select:
SELECT id, gym_id, name, created_at
FROM chat_rooms
WHERE gym_id = #{gymId}

SELECT id, gym_id, name, created_at
FROM chat_rooms
WHERE id = #{id}

SELECT id, room_id, user_id, joined_at, last_read_message_id, left_at
FROM chat_room_members
WHERE room_id = #{roomId} AND user_id = #{userId}

SELECT id, room_id, user_id, content, created_at, deleted_at
FROM chat_messages
WHERE id = #{id}
